mapper.select:
SELECT * FROM ( SELECT p.PAYMENT_ID, p.ORDER_ID, p.PAYMENT_METHOD, p.PAYMENT_STATUS, p.AMOUNT, p.CURRENCY, p.TRANSACTION_ID, p.CREATED_AT, o.USER_ID, u.EMAIL as USER_EMAIL, ROW_NUMBER() OVER (ORDER BY p.CREATED_AT DESC, p.PAYMENT_ID DESC) as RN FROM PAYMENTS p, ORDERS o, USERS u WHERE p.ORDER_ID = o.ORDER_ID AND o.USER_ID = u.USER_ID
AND p.PAYMENT_METHOD = #{paymentMethod}
AND p.PAYMENT_STATUS = #{paymentStatus}
AND p.CREATED_AT >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND p.CREATED_AT <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND p.AMOUNT >= #{minAmount}
AND p.AMOUNT <= #{maxAmount}
)
WHERE ROWNUM <= #{offset} + #{limit} AND RN > #{offset}
ORDER BY RN

SELECT COUNT(*) as count
FROM PAYMENTS p,
     ORDERS o
WHERE p.ORDER_ID = o.ORDER_ID

    AND p.PAYMENT_METHOD = #{paymentMethod}


    AND p.PAYMENT_STATUS = #{paymentStatus}


     AND p.CREATED_AT >= TO_DATE(#{startDate}, 'YYYY-MM-DD') 


     AND p.CREATED_AT <= TO_DATE(#{endDate}, 'YYYY-MM-DD') 


     AND p.AMOUNT >= #{minAmount} 


     AND p.AMOUNT <= #{maxAmount}
